{
  "lean_declaration": "theorem det_swap_cols (A : Matrix (Fin n) (Fin n) K) (i j : Fin n) (hij : i ≠ j) :\n    (A.submatrix id (Equiv.swap i j)).det = -A.det :=\n  calc\n    (A.submatrix id (Equiv.swap i j)).det = ((A.submatrix id (Equiv.swap i j)).transpose).det := by\n      simpa using (Matrix.det_transpose (A.submatrix id (Equiv.swap i j))).symm\n    _ = (A.transpose.submatrix (Equiv.swap i j) id).det := by simp [Matrix.submatrix_transpose]\n    _ = -(A.transpose).det := by simpa using det_swap_rows (A.transpose) i j hij\n    _ = -A.det := by simp [Matrix.det_transpose]",
  "declaration_name": "det_swap_cols",
  "used_context": [
    "det_swap_rows",
    "Matrix.det_transpose",
    "Matrix.submatrix_transpose"
  ],
  "notes": [
    "Column swap reduces to row swap of the transpose via det(A^T) = det(A)."
  ]
}
